<script>
import Playing from '../../../../utils/common/playing';

import defaultTemplate from '../../../../utils/defaultTemplate'
import {
	mapState
} from 'pinia';
import AppInfoStore from "@/store/modules/appInfoStore";
export default {
	name: "Betting",
	props: {
		zIndex: {
			type: [Number, String],
			default: () => {
				return 10075
			}
		}
	},
	data() {
		return {
			show: false,
			callback: null,
			playing: new Playing(),
			playName: '',
			winAmount: '',
		}
	},
	computed: {
    ...mapState(AppInfoStore, ['themeColor']),
	},
	methods: {
		open(data, {
			callback
		}) {
			if (data.source === 3 && this.playing.getStorage('isWin')) {
				this.show = true
				this.callback = callback

				let obj = JSON.parse(data.msgTxt);
				const {
					playName,
					winAmount
				} = defaultTemplate({
					playName: '',
					winAmount: '',
				}, obj)
				this.playName = playName
				this.winAmount = winAmount
				// 3秒自动关闭
				setTimeout(() => {
					this.close()
				}, 3000)
			}
		},
		close() {
			this.show = false
		},
		handleOpen() {
			this.$emit('open')
			this.callback && this.callback({
				type: 'open'
			})
		},
		handleClose() {
			this.$emit('close')
			this.callback && this.callback({
				type: 'close'
			})
		},
		setAmount(num) {
			return this.playing.setAmount(num, 2, '.', ',')
		},
	}
}
</script>

